a.t-attf-style:
margin-left:0px;
border:1px solid #064526;
background: #{ (not lv.leave_notification_id.is_downloaded) and '#064526' or '#ffffff' };
color: #{ (not lv.leave_notification_id.is_downloaded) and '#ffffff' or '#064526' };

span.style:
display: inline-block;
font-size: 12px;
color: #888;
padding: 6px 12px;
border: 1px dashed #ccc;
border-radius: 6px;
background: #f5f5f5;
min-width: 100px;
text-align: center;
white-space: normal;
overflow-wrap: break-word;
